import { useEffect, useRef, useState } from 'react';
import { getLastReplay } from '../../state/replay-store';
import { trapFocus } from '../a11y/trap-focus';
import './replay.css';

interface Props { onClose: () => void; }

/**
 * Replay viewer — scrubber + play button. Renders the captured frames onto a
 * canvas, scaling cells to fit a 280px box. The "Play" button time-lapses the
 * whole solve in ~10 seconds.
 *
 * Lazy-loaded so its ~1.5 KB gz stays out of the boot bundle.
 */
export function ReplayViewer({ onClose }: Props) {
  const ref = useRef<HTMLDivElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [frame, setFrame] = useState(0);
  const [playing, setPlaying] = useState(false);
  const replay = useRef(getLastReplay()).current;

  const frames = replay?.frames ?? [];

  // Focus trap + Escape
  useEffect(() => {
    const node = ref.current;
    if (!node) return;
    const release = trapFocus(node);
    function onKey(e: KeyboardEvent) { if (e.key === 'Escape') onClose(); }
    window.addEventListener('keydown', onKey);
    return () => { release(); window.removeEventListener('keydown', onKey); };
  }, [onClose]);

  // Repaint canvas whenever the frame index changes.
  useEffect(() => {
    if (!replay) return;
    const c = canvasRef.current;
    if (!c) return;
    const dpr = Math.min(2, window.devicePixelRatio || 1);
    const { rows, cols } = replay;
    const target = 280;
    const cellPx = Math.max(4, Math.floor(target / Math.max(rows, cols)));
    const w = cellPx * cols, h = cellPx * rows;
    c.width = w * dpr; c.height = h * dpr;
    c.style.width = `${w}px`; c.style.height = `${h}px`;
    const ctx = c.getContext('2d');
    if (!ctx) return;
    ctx.scale(dpr, dpr);
    const cs = getComputedStyle(document.documentElement);
    const paper = cs.getPropertyValue('--paper').trim() || '#ffffff';
    const ink = cs.getPropertyValue('--ink').trim() || '#1c1c1e';
    const cross = cs.getPropertyValue('--cross-mark').trim() || 'rgba(28,28,30,0.32)';
    ctx.fillStyle = paper;
    ctx.fillRect(0, 0, w, h);
    const f = frames[frame];
    if (!f) return;
    for (let r = 0; r < rows; r++) {
      for (let col = 0; col < cols; col++) {
        const mark = f.cells[r * cols + col];
        if (mark === 'fill') {
          ctx.fillStyle = ink;
          ctx.fillRect(col * cellPx, r * cellPx, cellPx, cellPx);
        } else if (mark === 'cross') {
          ctx.strokeStyle = cross;
          ctx.lineWidth = Math.max(1, cellPx * 0.12);
          const pad = cellPx * 0.28;
          ctx.beginPath();
          ctx.moveTo(col * cellPx + pad, r * cellPx + pad);
          ctx.lineTo(col * cellPx + cellPx - pad, r * cellPx + cellPx - pad);
          ctx.moveTo(col * cellPx + cellPx - pad, r * cellPx + pad);
          ctx.lineTo(col * cellPx + pad, r * cellPx + cellPx - pad);
          ctx.stroke();
        }
      }
    }
    // Faint grid for readability
    ctx.strokeStyle = 'rgba(0,0,0,0.08)';
    ctx.lineWidth = 1;
    for (let r = 1; r < rows; r++) {
      ctx.beginPath();
      ctx.moveTo(0, r * cellPx);
      ctx.lineTo(w, r * cellPx);
      ctx.stroke();
    }
    for (let col = 1; col < cols; col++) {
      ctx.beginPath();
      ctx.moveTo(col * cellPx, 0);
      ctx.lineTo(col * cellPx, h);
      ctx.stroke();
    }
  }, [frame, replay, frames]);

  // Playback engine — advance one frame per (10_000 / frames.length) ms so the
  // whole replay finishes in ~10s regardless of how many moves the solver took.
  useEffect(() => {
    if (!playing) return;
    const interval = Math.max(20, 10_000 / Math.max(1, frames.length - 1));
    let raf = 0;
    let last = performance.now();
    let acc = 0;
    let local = frame;
    const tick = (now: number) => {
      acc += now - last;
      last = now;
      while (acc >= interval) {
        acc -= interval;
        local += 1;
        if (local >= frames.length) { setPlaying(false); setFrame(frames.length - 1); return; }
      }
      setFrame(local);
      raf = requestAnimationFrame(tick);
    };
    raf = requestAnimationFrame(tick);
    return () => cancelAnimationFrame(raf);
  // We deliberately don't depend on `frame` to avoid restart-loop.
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [playing, frames.length]);

  if (!replay || frames.length < 2) {
    return (
      <div className="etch-replay-backdrop" role="dialog" aria-modal="true" aria-label="Replay" onClick={onClose}>
        <div className="etch-replay-sheet" ref={ref} onClick={(e) => e.stopPropagation()}>
          <header>
            <h2>Replay</h2>
            <button className="etch-replay-close" aria-label="Close" onClick={onClose}>×</button>
          </header>
          <p className="etch-replay-empty">No replay captured yet. Win a puzzle to record one.</p>
        </div>
      </div>
    );
  }

  return (
    <div className="etch-replay-backdrop" role="dialog" aria-modal="true" aria-label="Replay" onClick={onClose}>
      <div className="etch-replay-sheet" ref={ref} onClick={(e) => e.stopPropagation()}>
        <header>
          <h2>Replay</h2>
          <button className="etch-replay-close" aria-label="Close" onClick={onClose}>×</button>
        </header>
        <div className="etch-replay-canvas">
          <canvas ref={canvasRef} aria-label={`Frame ${frame + 1} of ${frames.length}`} />
        </div>
        <div className="etch-replay-controls">
          <button
            type="button"
            className="etch-replay-play"
            onClick={() => {
              if (frame === frames.length - 1) setFrame(0);
              setPlaying(p => !p);
            }}
          >
            {playing ? 'Pause' : (frame === frames.length - 1 ? 'Replay' : 'Play')}
          </button>
          <input
            type="range"
            min={0}
            max={frames.length - 1}
            value={frame}
            onChange={(e) => { setPlaying(false); setFrame(Number(e.target.value)); }}
            aria-label="Move timeline"
            className="etch-replay-scrub"
          />
          <span className="etch-replay-counter" aria-live="off">{frame + 1} / {frames.length}</span>
        </div>
      </div>
    </div>
  );
}

export default ReplayViewer;
